commits.content:
.productos {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 24px;
  padding: 24px;
}

.producto-card {
  background: #fff;
  border-radius: 12px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  padding: 20px;
  display: flex;
  flex-direction: column;
  align-items: center;
  transition: box-shadow 0.2s;
}
.producto-card:hover {
  box-shadow: 0 4px 16px rgba(0,0,0,0.15);
}
.producto-card img {
  width: 100%;
  max-width: 180px;
  border-radius: 8px;
  margin-bottom: 12px;
}
.producto-card h3 {
  margin: 10px 0 6px 0;
  font-size: 1.1rem;
}
.producto-card p {
  font-size: 0.95rem;
  color: #555;
  margin-bottom: 8px;
  text-align: center;
}
.producto-card strong {
  color: #1a8917;
  margin-bottom: 10px;
  font-size: 1.1rem;
}
.producto-card button {
  background: #1a8917;
  color: #fff;
  border: none;
  border-radius: 6px;
  padding: 8px 18px;
  font-size: 1rem;
  cursor: pointer;
  transition: background 0.2s;
}
.producto-card button:hover {
  background: #166d13;
}
